import React from "react";
import { Switch, Route } from "react-router-dom";
import RPAdmin from "./np-admin/app";

const Routes = () => {
	return (
		<Switch>
			<Route exact path="/" component={RPAdmin} />
		</Switch>
	);
};

export default Routes;
